text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        {
          "항목": "공개 릴리스 목표",
          "내용": "스모크 테스트 통과 시 금요일 15:00 KST 공개 릴리스로 확정."
        },
        {
          "항목": "packageName mismatch 대응",
          "내용": "smoke-theme-pack.mjs에서 packageName 불일치 시 무조건 무시하지 않음. 우선 패키지 설정을 점검하고, 계약 자체가 잘못된 경우에만 스크립트를 리뷰."
        },
        {
          "항목": "확정 액션",
          "내용": "Minjun은 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유."
        },
        {
          "항목": "확정 액션",
          "내용": "Doyun은 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성."
        },
        {
          "항목": "확정 액션(조건부 기한)",
          "내용": "Hara는 Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인."
        }
      ],
      "rejected_proposals": [
        {
          "항목": "smoke-theme-pack.mjs 수정 제안 반려",
          "내용": "Hara의 제안(패키지명 불일치 시 무시하도록 스크립트 변경)은 반려됨."
        }
      ],
      "internal_stretch_goals": [
        {
          "항목": "수요일 릴리스 목표",
          "내용": "수요일 공개 릴리스는 내부 스트레치 목표로만 설정됨(강제 마감 아님)."
        }
      ]
    },
    "non_decisions": [
      {
        "항목": "README 검토 담당자",
        "내용": "README 설치 단계는 목요일까지 검토한다는 제안만 있었고, 담당자는 미지정."
      },
      {
        "항목": "Hara의 세부 마감시한",
        "내용": "Hara의 tarball 경로 확인에 대한 정확한 기한은 미설정."
      },
      {
        "항목": "릴리스 노트 문구",
        "내용": "수요일 스트레치 목표를 릴리스 노트에 반영할지 여부는 미결정."
      }
    ],
    "risks": [
      {
        "항목": "tarball 경로 오류",
        "내용": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음."
      },
      {
        "항목": "README 설치 단계 노후",
        "내용": "README 설치 절차가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "항목": "최종 릴리스 승인 권한",
        "내용": "최종 릴리스 승인 권한자는 누구인지 미확정."
      },
      {
        "항목": "수요일 목표 공개 여부",
        "내용": "내부 스트레치 목표인 수요일 일정을 릴리스 노트에 명시할지 여부 미결정."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 테스트 결과 공개 후 생성된 tarball 경로 확인",
      "due": "Minjun 결과 공유 후",
      "status": "조건부 진행",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목요일(가능한 경우)",
      "status": "미할당(보류)",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "next": [
      "금요일 10:00 KST 전에 Minjun의 스모크 테스트 결과를 확인한다.",
      "결과 공유 즉시 Hara가 tarball 경로 확인을 수행했는지 추적한다.",
      "Doyun의 금요일 12:00 KST 실패 트리아지 노트 제출 여부를 확인한다.",
      "README 설치 단계 리뷰 담당자 미지정 상태와 목요일 검토 완료 여부를 보완한다.",
      "최종 승인 권한자와 릴리스 노트의 수요일 목표 표기 여부를 다음 회의에서 확정한다."
    ],
    "what_not_to_invent": [
      "고객명, 파트너명, 예산, 보안사고, 실제 장애, 법무 승인 요건은 회의록에 없음.",
      "최종 승인권자, README 리뷰 담당자, Hara의 정확한 tarball 검토 기한은 회의에서 미지정.",
      "수요일 목표를 공개 목표로 전환하거나 승인 상태를 임의로 추정해 기록하지 않음."
    ]
  },
  "non_invention_rules": [
    "명시된 항목만 사용하고, 제공되지 않은 사실(고객/예산/보안/장애/법무/소유자/최종 마감일)은 추론/추가 생성하지 않는다.",
    "마감 시간이 누락된 항목은 반드시 '미지정' 또는 '미결정'으로만 표시한다.",
    "합의되지 않은 내부/외부 경계(예: 내부 스트레치 목표의 공개 반영 여부)는 별도 결재 없이 단정하지 않는다.",
    "이 출력은 공개 안전 합성 fixture 기준으로만 작성하고, 외부 사실이나 추정 참조를 사용하지 않는다."
  ]
}
